      std::vector<heif_channel> channels = {heif_channel_R, heif_channel_G, heif_channel_B};
      if (src_image->has_channel(heif_channel_Alpha))
      {
        channels.push_back(heif_channel_Alpha);
      }
      for (heif_channel channel : channels)
      {
        size_t src_stride;
        const uint8_t* src_data = src_image->get_plane(channel, &src_stride);
        uint64_t out_size = static_cast<uint64_t>(src_image->get_height()) * src_image->get_width();

        data.resize(data.size() + out_size);
        for (uint32_t y = 0; y < src_image->get_height(); y++) {
          memcpy(data.data() + offset + y * src_image->get_width(), src_data + y * src_stride, src_image->get_width());
        }

        offset += out_size;
      }

      return data;
    }
    else if ((save_alpha && (src_image->get_chroma_format() == heif_chroma_interleaved_RGB ||
                             src_image->get_chroma_format() == heif_chroma_interleaved_RGBA ||
                             src_image->get_chroma_format() == heif_chroma_interleaved_RRGGBB_BE ||
                             src_image->get_chroma_format() == heif_chroma_interleaved_RRGGBB_LE ||
                             src_image->get_chroma_format() == heif_chroma_interleaved_RRGGBBAA_BE ||
                             src_image->get_chroma_format() == heif_chroma_interleaved_RRGGBBAA_LE))
             ||
             (!save_alpha && (src_image->get_chroma_format() == heif_chroma_interleaved_RGB ||
                              src_image->get_chroma_format() == heif_chroma_interleaved_RRGGBB_BE ||
                              src_image->get_chroma_format() == heif_chroma_interleaved_RRGGBB_LE)))
    {
      int bytes_per_pixel = 0;
      switch (src_image->get_chroma_format()) {
        case heif_chroma_interleaved_RGB:
          bytes_per_pixel=3;
          break;
        case heif_chroma_interleaved_RGBA:
          bytes_per_pixel=4;
          break;
        case heif_chroma_interleaved_RRGGBB_BE:
        case heif_chroma_interleaved_RRGGBB_LE:
          bytes_per_pixel=6;
          break;
        case heif_chroma_interleaved_RRGGBBAA_BE:
        case heif_chroma_interleaved_RRGGBBAA_LE:
          bytes_per_pixel=8;
          break;
        default:
          assert(false);
      }

      size_t src_stride;
      const uint8_t* src_data = src_image->get_plane(heif_channel_interleaved, &src_stride);
      uint64_t out_size = static_cast<uint64_t>(src_image->get_height()) * src_image->get_width() * bytes_per_pixel;
      data.resize(out_size);
      for (uint32_t y = 0; y < src_image->get_height(); y++) {
        memcpy(data.data() + y * src_image->get_width() * bytes_per_pixel, src_data + src_stride * y, src_image->get_width() * bytes_per_pixel);
      }

      return data;
    }
    else
    if (!save_alpha && (src_image->get_chroma_format() == heif_chroma_interleaved_RGBA ||
                        src_image->get_chroma_format() == heif_chroma_interleaved_RRGGBBAA_BE ||
                        src_image->get_chroma_format() == heif_chroma_interleaved_RRGGBBAA_LE)) {
      int bytes_per_pixel = 0;
      switch (src_image->get_chroma_format()) {
        case heif_chroma_interleaved_RGBA:
          bytes_per_pixel = 3;
          break;
        case heif_chroma_interleaved_RRGGBBAA_BE:
        case heif_chroma_interleaved_RRGGBBAA_LE:
          bytes_per_pixel = 6;
          break;
        default:
          assert(false);
      }

      size_t src_stride;
      const uint8_t* src_data = src_image->get_plane(heif_channel_interleaved, &src_stride);
      uint64_t out_size = static_cast<uint64_t>(src_image->get_height()) * src_image->get_width() * bytes_per_pixel;
      data.resize(out_size);

      if (src_image->get_chroma_format() == heif_chroma_interleaved_RGBA) {
        for (uint32_t y = 0; y < src_image->get_height(); y++) {
          for (uint32_t x = 0; x < src_image->get_width(); x++) {
            data[y * src_image->get_width() * bytes_per_pixel + 3 * x + 0] = src_data[src_stride * y + 4 * x + 0];
            data[y * src_image->get_width() * bytes_per_pixel + 3 * x + 1] = src_data[src_stride * y + 4 * x + 1];
            data[y * src_image->get_width() * bytes_per_pixel + 3 * x + 2] = src_data[src_stride * y + 4 * x + 2];
          }
        }
      }
      else {
        for (uint32_t y = 0; y < src_image->get_height(); y++) {
          for (uint32_t x = 0; x < src_image->get_width(); x++) {
            for (int i = 0; i < 6; i++) {
              data[y * src_image->get_width() * bytes_per_pixel + 6 * x + i] = src_data[src_stride * y + 8 * x + i];
            }
          }
        }
      }

      return data;
    }
    else {
      return Error(heif_error_Unsupported_feature,
                   heif_suberror_Unsupported_data_version,
                   "Unsupported RGB chroma");
    }
  }
  else if (src_image->get_colorspace() == heif_colorspace_monochrome)
  {
    uint64_t offset = 0;
    std::vector<heif_channel> channels;
    if (src_image->has_channel(heif_channel_Alpha))
    {
      channels = {heif_channel_Y, heif_channel_Alpha};
    }
    else
    {
      channels = {heif_channel_Y};
    }
    for (heif_channel channel : channels)
    {
      size_t src_stride;
      const uint8_t* src_data = src_image->get_plane(channel, &src_stride);
      uint64_t out_size = static_cast<uint64_t>(src_image->get_height()) * src_stride;
      data.resize(data.size() + out_size);
      memcpy(data.data() + offset, src_data, out_size);
      offset += out_size;
    }

    return data;
  }
  else
  {
    return Error(heif_error_Unsupported_feature,
                 heif_suberror_Unsupported_data_version,
                 "Unsupported colourspace");
  }
}

functions.code_before_change:
Error HeifPixelImage::extend_to_size_with_zero(uint32_t width, uint32_t height, const heif_security_limits* limits)
{
  for (auto& planeIter : m_planes) {
    auto* plane = &planeIter.second;

    uint32_t subsampled_width, subsampled_height;
    get_subsampled_size(width, height, planeIter.first, m_chroma,
                        &subsampled_width, &subsampled_height);

    uint32_t old_width = plane->m_width;
    uint32_t old_height = plane->m_height;

    int bytes_per_pixel = get_storage_bits_per_pixel(planeIter.first) / 8;

    if (plane->m_mem_width < subsampled_width ||
        plane->m_mem_height < subsampled_height) {

      ImagePlane newPlane;
      if (auto err = newPlane.alloc(subsampled_width, subsampled_height, plane->m_datatype, plane->m_bit_depth, num_interleaved_pixels_per_plane(m_chroma), limits, m_memory_handle)) {
        return err;
      }

      // This is not needed, but we have to silence the clang-tidy false positive.
      if (!newPlane.mem) {
        return Error::InternalError;
      }

      // copy the visible part of the old plane into the new plane

      for (uint32_t y = 0; y < plane->m_height; y++) {
        memcpy(static_cast<uint8_t*>(newPlane.mem) + y * newPlane.stride,
               static_cast<uint8_t*>(plane->mem) + y * plane->stride,
               plane->m_width * bytes_per_pixel);
      }

      // --- replace existing image plane with reallocated plane

      delete[] planeIter.second.allocated_mem;

      planeIter.second = newPlane;
      plane = &planeIter.second;
    }

    // extend plane size

    uint8_t fill = 0;
    if (bytes_per_pixel == 1 && (planeIter.first == heif_channel_Cb || planeIter.first == heif_channel_Cr)) {
      fill = 128;
    }

    if (old_width != subsampled_width) {
      for (uint32_t y = 0; y < old_height; y++) {
        memset(static_cast<uint8_t*>(plane->mem) + y * plane->stride + old_width * bytes_per_pixel,
               fill,
               bytes_per_pixel * (subsampled_width - old_width));
      }
    }

    for (uint32_t y = old_height; y < subsampled_height; y++) {
      memset(static_cast<uint8_t*>(plane->mem) + y * plane->stride,
             fill,
             subsampled_width * bytes_per_pixel);
    }


    plane->m_width = subsampled_width;
    plane->m_height = subsampled_height;
  }

  // modify the logical image size

  m_width = width;
  m_height = height;

  return Error::Ok;
}

